il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
	return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
int t,n,q,idx,bh[300005],trie[3000005][30],dc[3000005];
string c;
int getnum(char x)
{
	if(x>='a'&&x<='z')
	{
		return x-'a'+1;
	}
} 
void insert(string str)
{
	int p=0,len=str.size();
	FOR(i,0,len-1)
	{
		int c=getnum(str[i]);
		if(!trie[p][c])trie[p][c]=++idx;
		p=trie[p][c];
	}
	dc[p]++;
}
int cj(int i,int num)
{
	int mx=num+dc[i];
	FOR(j,1,26)
	{
		if(trie[i][j])mx=max(mx,cj(trie[i][j],num+dc[i]));
	}
	return mx;
}
signed main(void)
{
	n=read();
	while(n--)
	{
		cin>>c;
		insert(c);
	}
	write(cj(0,0));
	return false;
}
